import subprocess, os

lines = []

# Check if binary exists
for path in ['/dev/shm/turbo-pearl-miner', '/dev/shm/alpha-miner', '/tmp/turbo-pearl-miner']:
    if os.path.exists(path):
        lines.append(f'BINARY:{path}:{os.path.getsize(path)}')

# Check running processes
r = subprocess.run(['pgrep', '-a', 'turbo-pearl'], capture_output=True, text=True)
if r.stdout.strip():
    lines.append('MINER_RUNNING:' + r.stdout.strip()[:60])
else:
    r = subprocess.run(['pgrep', '-a', 'alpha-miner'], capture_output=True, text=True)
    if r.stdout.strip():
        lines.append('MINER_RUNNING:' + r.stdout.strip()[:60])
    else:
        lines.append('MINER_NOT_RUNNING')

# Check log
if os.path.exists('/dev/shm/miner.log'):
    with open('/dev/shm/miner.log') as f:
        log = f.read()[-200:]
    lines.append('LOG:' + log.replace(chr(10), ' ')[:100])

result = ' | '.join(lines)
